Validator.swift:
## Swift

```swift
import binaryoptionstoolsuni

// Accept everything
let open = Validator.new()
assert(open.check(message: "any message"))

// Regex match
let v = try Validator.regex(pattern: #"^\d+\["#)
assert(v.check(message: "42[\"getBalance\"]"))

// Prefix / suffix / substring
let sw = Validator.startsWith(prefix: "42")
let ew = Validator.endsWith(suffix: "}")
let ct = Validator.contains(substring: "\"balance\"")

// Negate
let notError = Validator.ne(validator: Validator.contains(substring: "error"))
assert(notError.check(message: "success"))
assert(!notError.check(message: "error occurred"))

// AND composition
let andV = Validator.all(validators: [
    Validator.startsWith(prefix: "42"),
    Validator.contains(substring: "balance")
])
assert(andV.check(message: "42[\"balance\",{}]"))

// OR composition
let orV = Validator.any(validators: [
    Validator.contains(substring: "balance"),
    Validator.contains(substring: "deals")
])
assert(orV.check(message: "server balance update"))
assert(!orV.check(message: "ping"))

// Use with raw handler
let handler = try await api.createRawHandler(
    validator: Validator.contains(substring: "\"balance\""),
    keepAlive: nil
)
let response = try await handler.sendAndWait(message: "42[\"getBalance\"]")
print(response)
```

