## Go

```go
import bot "github.com/ChipaDevTeam/BinaryOptionsTools-v2"

// Accept everything
open := bot.ValidatorNew()
if !open.Check("any message") { panic("expected true") }

// Regex match
v, err := bot.ValidatorRegex(`^\d+\["`)
if err != nil { panic(err) }
if !v.Check(`42["getBalance"]`) { panic("expected true") }

// Prefix / suffix / substring
sw := bot.ValidatorStartsWith("42")
ew := bot.ValidatorEndsWith("}")
ct := bot.ValidatorContains(`"balance"`)
_ = sw; _ = ew; _ = ct

// Negate
notError := bot.ValidatorNe(bot.ValidatorContains("error"))
if !notError.Check("success") { panic("expected true") }
if notError.Check("error occurred") { panic("expected false") }

// AND composition
andV := bot.ValidatorAll([]bot.Validator{
    bot.ValidatorStartsWith("42"),
    bot.ValidatorContains("balance"),
})
if !andV.Check(`42["balance",{}]`) { panic("expected true") }

// OR composition
orV := bot.ValidatorAny([]bot.Validator{
    bot.ValidatorContains("balance"),
    bot.ValidatorContains("deals"),
})
if !orV.Check("server balance update") { panic("expected true") }
if orV.Check("ping") { panic("expected false") }

// Use with raw handler
handler, err := api.CreateRawHandler(bot.ValidatorContains(`"balance"`), nil)
if err != nil { panic(err) }
response, err := handler.SendAndWait(`42["getBalance"]`)
fmt.Println(response)
```

