    Validator.startsWith('42'),
    Validator.contains('balance'),
]);
console.assert(andV.check('42["balance",{}]') === true);
console.assert(andV.check('42["deals",{}]') === false);

// OR composition
const orV = Validator.any([
    Validator.contains('balance'),
    Validator.contains('deals'),
]);
console.assert(orV.check('server balance update') === true);
console.assert(orV.check('ping') === false);

// Use with raw handler
